// Sipariş validation
const siparis = $input.first().json.body;

const validation = {
  gecerli: !!siparis.musteriId && !!siparis.urunler && siparis.urunler.length > 0,
  urunSayisi: siparis.urunler?.length || 0,
  toplamTutar: siparis.toplamTutar || 0,
  hatalar: []
};

if (!siparis.musteriId) validation.hatalar.push('Müşteri ID eksik');
if (!siparis.urunler || siparis.urunler.length === 0) validation.hatalar.push('Ürün listesi boş');
if (!siparis.toplamTutar || siparis.toplamTutar <= 0) validation.hatalar.push('Geçersiz tutar');

return [{ json: { siparis, validation } }];

parameters.prompt:
Şu siparişi analiz et ve risk skorunu hesapla:

Sipariş Detayları:
- Müşteri ID: {{ $json.siparis.musteriId }}
- Ürün Sayısı: {{ $json.siparis.urunler?.length || 0 }}
- Toplam Tutar: ₺{{ $json.siparis.toplamTutar || 0 }}

Risk faktörlerini değerlendir:
1. Miktar anomalisi (normal: 1-10 adet)
2. Fiyat tutarsızlığı (piyasa ortalamasına göre)
3. Müşteri geçmişi (yeni müşteri mi?)

JSON formatında dön:
{
  "riskScore": 0-100,
  "riskLevel": "DÜŞÜK" | "ORTA" | "YÜKSEK",
  "riskFactors": [{ "factor": "...", "severity": "HIGH|MEDIUM|LOW", "description": "..." }],
  "action": "AUTO_APPROVE" | "MANUAL_REVIEW" | "REJECT"
}

