// Sipariş red işlemleri
const siparis = $input.first().json.siparis;

return [{
  json: {
    orderId: siparis.id,
    status: 'REJECTED',
    rejectedAt: new Date().toISOString(),
    reason: 'Yüksek risk skoru nedeniyle reddedildi'
  }
}];

// Sonucu logla
